SELECT *
  FROM sys07_role_menu
 WHERE sys07_role_id IN (
           SELECT sys04_role_id FROM sys04_role
            WHERE sys04_company_id = #{companyId}
              AND sys04_role_nm = #{roleName}
       )
   AND sys07_menu_id = #{menuId}

mapper.update:
UPDATE sys07_role_menu
   SET sys07_use_yn = #{useYn},
       sys07_note   = #{note}
 WHERE sys07_role_menu_id = #{roleMenuId}
